import torch
import torch.nn.functional as F
from torchvision import models, transforms
from PIL import Image
import io
import hashlib
import os
from flask import Flask, request, jsonify
from flask_limiter import Limiter
from flask_limiter.util import get_remote_address
import numpy as np

app = Flask(__name__)

# Load pre-trained model
model = models.resnet50(pretrained=True)
model.eval()

# Secure preprocessing with noise reduction
preprocess = transforms.Compose([
    transforms.Resize(256),
    transforms.CenterCrop(224),
    transforms.ToTensor(),
])

# Rate limiting
limiter = Limiter(
    app,
    key_func=get_remote_address,
    default_limits=["100 per hour"]
)

# Secure hash for input validation
def generate_input_hash(image_data):
    return hashlib.sha256(image_data).hexdigest()

# Adversarial detection
def detect_adversarial_input(image_tensor):
    # Simple check for extreme values that might indicate adversarial examples
    if torch.any(torch.isnan(image_tensor)) or torch.any(torch.isinf(image_tensor)):
        return True
    if torch.max(image_tensor) > 1.0 or torch.min(image_tensor) < 0.0:
        return True
    return False

@app.route('/classify', methods=['POST'])
@limiter.limit("10 per minute")
def classify_image():
    try:
        if 'image' not in request.files:
            return jsonify({'error': 'No image provided'}), 400
            
        file = request.files['image']
        if file.filename == '':
            return jsonify({'error': 'No image selected'}), 400
            
        # Read image
        image_data = file.read()
        
        # Input validation
        if len(image_data) == 0:
            return jsonify({'error': 'Empty image data'}), 400
            
        # Generate hash for input tracking
        input_hash = generate_input_hash(image_data)
        
        # Load image
        image = Image.open(io.BytesIO(image_data)).convert('RGB')
        
        # Apply preprocessing
        input_tensor = preprocess(image)
        input_batch = input_tensor.unsqueeze(0)
        
        # Adversarial detection
        if detect_adversarial_input(input_batch):
            return jsonify({'error': 'Invalid input detected'}), 400
            
        # Run inference
        with torch.no_grad():
            output = model(input_batch)
            probabilities = F.softmax(output, dim=1)
            confidence, predicted = torch.max(probabilities, 1)
            
        # Return results
        return jsonify({
            'class': predicted.item(),
            'confidence': confidence.item()
        })
        
    except Exception as e:
        return jsonify({'error': 'Processing failed'}), 500

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000, threaded=True)